diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 4d3de76389c2..f9ac46be885a 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3203,6 +3203,34 @@ Instruction *InstCombinerImpl::foldSelectOfBools(SelectInst &SI) {
       match(TrueVal, m_Specific(B)) && match(FalseVal, m_Zero()))
     return replaceOperand(SI, 0, A);

+  // select (select a, b, false), c, false -> select a, (select b, c, false), false
+  // This is valid if the inner select can be simplified to an and.
+  if (match(CondVal, m_OneUse(m_Select(m_Value(A), m_Value(B), m_Zero()))) &&
+      match(FalseVal, m_Zero()) && impliesPoison(TrueVal, B)) {
+    Value *InnerSel = Builder.CreateSelect(B, TrueVal, Zero);
+    return SelectInst::Create(A, InnerSel, Zero);
+  }
+  // select c, (select a, b, false), false -> select a, (select b, c, false), false
+  // This is valid if the inner select can be simplified to an and.
+  if (match(TrueVal, m_OneUse(m_Select(m_Value(A), m_Value(B), m_Zero()))) &&
+      match(FalseVal, m_Zero()) && impliesPoison(CondVal, B)) {
+    Value *InnerSel = Builder.CreateSelect(B, CondVal, Zero);
+    return SelectInst::Create(A, InnerSel, Zero);
+  }
+  // select (select a, true, b), true, c -> select a, true, (select b, true, c)
+  // This is valid if the inner select can be simplified to an or.
+  if (match(CondVal, m_OneUse(m_Select(m_Value(A), m_One(), m_Value(B)))) &&
+      match(TrueVal, m_One()) && impliesPoison(FalseVal, B)) {
+    Value *InnerSel = Builder.CreateSelect(B, One, FalseVal);
+    return SelectInst::Create(A, One, InnerSel);
+  }
+  // select c, (select a, true, b), true -> select a, true, (select b, true, c)
+  // This is valid if the inner select can be simplified to an or.
+  if (match(TrueVal, m_OneUse(m_Select(m_Value(A), m_One(), m_Value(B)))) &&
+      match(FalseVal, m_One()) && impliesPoison(CondVal, B)) {
+    Value *InnerSel = Builder.CreateSelect(B, One, CondVal);
+    return SelectInst::Create(A, One, InnerSel);
+  }
   // ~(A & B) & (A | B) --> A ^ B
   if (match(&SI, m_c_LogicalAnd(m_Not(m_LogicalAnd(m_Value(A), m_Value(B))),
                                 m_c_LogicalOr(m_Deferred(A), m_Deferred(B)))))

